   646→// ============================================================
   647→// 인터럽트 설정/해제 함수
   648→// ============================================================
   649→void setupEncoder1Interrupts() {
   650→  attachInterrupt(digitalPinToInterrupt(ENC1_PIN_A), enc1_isr, CHANGE);
   651→  attachInterrupt(digitalPinToInterrupt(ENC1_PIN_B), enc1_isr, CHANGE);
   652→}
   653→
   654→void setupEncoder2Interrupts() {
   655→  attachInterrupt(digitalPinToInterrupt(ENC2_PIN_A), enc2_isr, CHANGE);
   656→  attachInterrupt(digitalPinToInterrupt(ENC2_PIN_B), enc2_isr, CHANGE);
   657→}
   658→
   659→void setupEncoder3Interrupts() {
   660→  attachInterrupt(digitalPinToInterrupt(ENC3_PIN_A), enc3_isr, CHANGE);
   661→  attachInterrupt(digitalPinToInterrupt(ENC3_PIN_B), enc3_isr, CHANGE);
   662→}
   663→
   664→// ============================================================
   665→// 초기화
   666→// ============================================================
   667→void setup() {
   668→  // 시리얼 초기화
   669→  Serial.begin(SERIAL_BAUD);
   670→  while (!Serial) { delay(10); }
   671→  
   672→  // 핀 설정 - Encoder 1
   673→  pinMode(ENC1_PIN_A, INPUT);
   674→  pinMode(ENC1_PIN_B, INPUT);
   675→  pinMode(ENC1_PIN_Z, INPUT);
   676→  
   677→  // 핀 설정 - Encoder 2
   678→  pinMode(ENC2_PIN_A, INPUT);
   679→  pinMode(ENC2_PIN_B, INPUT);
   680→  pinMode(ENC2_PIN_Z, INPUT);
   681→  
   682→  // 핀 설정 - Encoder 3
   683→  pinMode(ENC3_PIN_A, INPUT);
   684→  pinMode(ENC3_PIN_B, INPUT);
   685→  pinMode(ENC3_PIN_Z, INPUT);
   686→  
   687→  // NVS에서 저장된 값 불러오기
   688→  loadOffsets();
   689→  loadPositions();
   690→  loadEnabledState();
   691→  
   692→  // 초기 상태 읽기
   693→  enc1_last_state = (digitalRead(ENC1_PIN_B) << 1) | digitalRead(ENC1_PIN_A);
   694→  enc2_last_state = (digitalRead(ENC2_PIN_B) << 1) | digitalRead(ENC2_PIN_A);
   695→  enc3_last_state = (digitalRead(ENC3_PIN_B) << 1) | digitalRead(ENC3_PIN_A);
   696→  
   697→  // 인터럽트 설정 (모든 엔코더에 대해 설정, 활성화 여부와 무관하게)
   698→  // 비활성화된 엔코더도 인터럽트는 유지하고, 출력만 제어
   699→  setupEncoder1Interrupts();
   700→  setupEncoder2Interrupts();
   701→  setupEncoder3Interrupts();
   702→  
   703→  // 시작 시간 기록
   704→  start_time = millis();
   705→  last_update_time = start_time;
   706→  
   707→  // 시작 메시지
   708→  Serial.print("{\"msg\":\"ESP32 Triple Encoder Ready\"");
   709→  Serial.print(",\"active_encoders\":");
   710→  Serial.print(getActiveEncoderCount());
   711→  if (enc1_enabled) { Serial.print(",\"e1_offset\":"); Serial.print(enc1_offset); }
   712→  if (enc2_enabled) { Serial.print(",\"e2_offset\":"); Serial.print(enc2_offset); }
   713→  if (enc3_enabled) { Serial.print(",\"e3_offset\":"); Serial.print(enc3_offset); }
   714→  Serial.print(",\"e1_en\":");
   715→  Serial.print(enc1_enabled ? "true" : "false");
   716→  Serial.print(",\"e2_en\":");
   717→  Serial.print(enc2_enabled ? "true" : "false");
   718→  Serial.print(",\"e3_en\":");
   719→  Serial.print(enc3_enabled ? "true" : "false");
   720→  Serial.println(",\"ok\":true}");
   721→  
   722→  delay(100);
   723→}
   724→
   725→// ============================================================
   726→// 메인 루프
   727→// ============================================================
   728→void loop() {
   729→  unsigned long current_time = millis();
   730→  
   731→  // 주기적 데이터 전송
   732→  if (current_time - last_update_time >= UPDATE_INTERVAL_MS) {
   733→    last_update_time = current_time;
   734→    sendEncoderData();
   735→  }
   736→  
   737→  // 시리얼 명령 수신
   738→  while (Serial.available() > 0) {
   739→    char c = Serial.read();
   740→    if (c == '\n' || c == '\r') {
   741→      if (serial_buffer.length() > 0) {
   742→        processCommand(serial_buffer);
   743→        serial_buffer = "";
   744→      }
   745→    } else {
   746→      serial_buffer += c;
   747→      if (serial_buffer.length() > 64) {
   748→        serial_buffer = "";
   749→      }
   750→    }
   751→  }
   752→}
