   201→    // 정기구학 계산
   202→    private void CalculateJoints()
   203→    {
   204→        if (!double.TryParse(txtL1.Text, out double L1)) L1 = 100;
   205→        if (!double.TryParse(txtL2.Text, out double L2)) L2 = 80;
   206→        if (!double.TryParse(txtL3.Text, out double L3)) L3 = 60;
   207→
   208→        // 라디안 변환
   209→        double t1 = theta1 * Math.PI / 180.0;
   210→        double t2 = theta2 * Math.PI / 180.0;
   211→        double t3 = theta3 * Math.PI / 180.0;
   212→
   213→        // 누적 각도
   214→        double sum1 = t1;
   215→        double sum2 = t1 + t2;
   216→        double sum3 = t1 + t2 + t3;
   217→
   218→        // 관절 좌표 계산 (3R Planar - XY 평면)
   219→        joints[0] = new PointF3D(0, 0, 0);  // 베이스
   220→
   221→        // 축1 끝 (베이스 중심, Z축 높이만)
   222→        joints[1] = new PointF3D(0, 0, 20);
   223→
   224→        // 축1 → 축2
   225→        joints[2] = new PointF3D(
   226→            L1 * Math.Cos(sum1),
   227→            L1 * Math.Sin(sum1),
   228→            20
   229→        );
   230→
   231→        // 축2 → 축3
   232→        joints[3] = new PointF3D(
   233→            L1 * Math.Cos(sum1) + L2 * Math.Cos(sum2),
   234→            L1 * Math.Sin(sum1) + L2 * Math.Sin(sum2),
   235→            20
   236→        );
   237→
   238→        // 축3 → 툴
   239→        joints[4] = new PointF3D(
   240→            L1 * Math.Cos(sum1) + L2 * Math.Cos(sum2) + L3 * Math.Cos(sum3),
   241→            L1 * Math.Sin(sum1) + L2 * Math.Sin(sum2) + L3 * Math.Sin(sum3),
   242→            20
   243→        );
   244→
   245→        // 결과 표시
   246→        lblResult.Text = $"툴 좌표:\nX: {joints[4].X:F2} mm\nY: {joints[4].Y:F2} mm";
   247→    }
