   249→    // 3D → 2D 투영 (등각 투영)
   250→    private PointF Project3D(PointF3D p, int centerX, int centerY)
   251→    {
   252→        double radX = viewAngleX * Math.PI / 180.0;
   253→        double radZ = viewAngleZ * Math.PI / 180.0;
   254→
   255→        // Z축 회전 (좌우)
   256→        double x1 = p.X * Math.Cos(radZ) - p.Y * Math.Sin(radZ);
   257→        double y1 = p.X * Math.Sin(radZ) + p.Y * Math.Cos(radZ);
   258→        double z1 = p.Z;
   259→
   260→        // X축 회전 (상하)
   261→        double y2 = y1 * Math.Cos(radX) - z1 * Math.Sin(radX);
   262→        double z2 = y1 * Math.Sin(radX) + z1 * Math.Cos(radX);
   263→
   264→        // 2D 투영 + 팬 오프셋 적용
   265→        float screenX = (float)(centerX + x1 * zoom + panOffsetX);
   266→        float screenY = (float)(centerY - z2 * zoom + panOffsetY);
   267→
   268→        return new PointF(screenX, screenY);
   269→    }
