   272→    private void PicViewer_Paint(object? sender, PaintEventArgs e)
   273→    {
   274→        Graphics g = e.Graphics;
   275→        g.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;
   276→
   277→        int centerX = picViewer.Width / 2;
   278→        int centerY = picViewer.Height / 2;
   279→
   280→        // 그리드 그리기
   281→        DrawGrid(g, centerX, centerY);
   282→
   283→        // 축 그리기 (X: 빨강, Y: 초록, Z: 파랑)
   284→        DrawAxis(g, centerX, centerY);
   285→
   286→        // 로봇암 그리기
   287→        DrawRobotArm(g, centerX, centerY);
   288→    }
