   290→    // 그리드 그리기
   291→    private void DrawGrid(Graphics g, int cx, int cy)
   292→    {
   293→        using Pen gridPen = new Pen(Color.FromArgb(60, 60, 60), 1);
   294→        int gridSize = 50;
   295→        int range = 300;
   296→
   297→        for (int i = -range; i <= range; i += gridSize)
   298→        {
   299→            // X 방향 선
   300→            PointF p1 = Project3D(new PointF3D(i, -range, 0), cx, cy);
   301→            PointF p2 = Project3D(new PointF3D(i, range, 0), cx, cy);
   302→            g.DrawLine(gridPen, p1, p2);
   303→
   304→            // Y 방향 선
   305→            p1 = Project3D(new PointF3D(-range, i, 0), cx, cy);
   306→            p2 = Project3D(new PointF3D(range, i, 0), cx, cy);
   307→            g.DrawLine(gridPen, p1, p2);
   308→        }
   309→    }
   310→
   311→    // 좌표축 그리기
   312→    private void DrawAxis(Graphics g, int cx, int cy)
   313→    {
   314→        int len = 100;
   315→        using Pen xPen = new Pen(Color.Red, 2);
   316→        using Pen yPen = new Pen(Color.LimeGreen, 2);
   317→        using Pen zPen = new Pen(Color.DodgerBlue, 2);
   318→        using Font axisFont = new Font("Arial", 10, FontStyle.Bold);
   319→
   320→        PointF origin = Project3D(new PointF3D(0, 0, 0), cx, cy);
   321→        PointF xEnd = Project3D(new PointF3D(len, 0, 0), cx, cy);
   322→        PointF yEnd = Project3D(new PointF3D(0, len, 0), cx, cy);
   323→        PointF zEnd = Project3D(new PointF3D(0, 0, len), cx, cy);
   324→
   325→        g.DrawLine(xPen, origin, xEnd);
   326→        g.DrawLine(yPen, origin, yEnd);
   327→        g.DrawLine(zPen, origin, zEnd);
   328→
   329→        g.DrawString("X", axisFont, Brushes.Red, xEnd);
   330→        g.DrawString("Y", axisFont, Brushes.LimeGreen, yEnd);
   331→        g.DrawString("Z", axisFont, Brushes.DodgerBlue, zEnd);
   332→    }
   333→
   334→    // 로봇암 그리기
   335→    private void DrawRobotArm(Graphics g, int cx, int cy)
   336→    {
   337→        // 베이스 원
   338→        using Pen basePen = new Pen(Color.Gray, 3);
   339→        PointF baseCenter = Project3D(joints[0], cx, cy);
   340→        g.DrawEllipse(basePen, baseCenter.X - 20, baseCenter.Y - 10, 40, 20);
   341→
   342→        // 링크 색상
   343→        Color[] linkColors = { Color.Orange, Color.Orange, Color.Cyan, Color.Magenta };
   344→        int[] linkWidths = { 8, 6, 5, 4 };
   345→
   346→        // 링크 그리기
   347→        for (int i = 1; i < joints.Length; i++)
   348→        {
   349→            PointF p1 = Project3D(joints[i - 1], cx, cy);
   350→            PointF p2 = Project3D(joints[i], cx, cy);
   351→
   352→            using Pen linkPen = new Pen(linkColors[i - 1], linkWidths[i - 1]);
   353→            linkPen.StartCap = System.Drawing.Drawing2D.LineCap.Round;
   354→            linkPen.EndCap = System.Drawing.Drawing2D.LineCap.Round;
   355→            g.DrawLine(linkPen, p1, p2);
   356→        }
   357→
   358→        // 관절 그리기
   359→        for (int i = 1; i < joints.Length; i++)
   360→        {
   361→            PointF p = Project3D(joints[i], cx, cy);
   362→            int r = (i == joints.Length - 1) ? 8 : 6;  // 툴은 좀 더 크게
   363→            Color c = (i == joints.Length - 1) ? Color.Red : Color.Yellow;
   364→
   365→            using SolidBrush brush = new SolidBrush(c);
   366→            g.FillEllipse(brush, p.X - r, p.Y - r, r * 2, r * 2);
   367→            g.DrawEllipse(Pens.White, p.X - r, p.Y - r, r * 2, r * 2);
   368→        }
   369→
   370→        // 툴 좌표 텍스트
   371→        PointF toolPos = Project3D(joints[4], cx, cy);
   372→        using Font font = new Font("Consolas", 9);
   373→        string toolText = $"({joints[4].X:F1}, {joints[4].Y:F1})";
   374→        g.DrawString(toolText, font, Brushes.White, toolPos.X + 10, toolPos.Y - 20);
   375→    }
