   377→    // 마우스 이벤트 (3D 뷰 회전 / 팬 이동)
   378→    private void PicViewer_MouseDown(object? sender, MouseEventArgs e)
   379→    {
   380→        lastMouse = e.Location;
   381→
   382→        // 좌우 동시 클릭 = 팬 이동
   383→        if (e.Button == (MouseButtons.Left | MouseButtons.Right) ||
   384→            (e.Button == MouseButtons.Left && (Control.MouseButtons & MouseButtons.Right) != 0) ||
   385→            (e.Button == MouseButtons.Right && (Control.MouseButtons & MouseButtons.Left) != 0))
   386→        {
   387→            isPanning = true;
   388→            isDragging = false;
   389→            picViewer.Cursor = Cursors.Hand;
   390→        }
   391→        // 좌클릭만 = 회전
   392→        else if (e.Button == MouseButtons.Left)
   393→        {
   394→            isDragging = true;
   395→            isPanning = false;
   396→            picViewer.Cursor = Cursors.SizeAll;
   397→        }
   398→    }
   399→
   400→    private void PicViewer_MouseMove(object? sender, MouseEventArgs e)
   401→    {
   402→        int dx = e.X - lastMouse.X;
   403→        int dy = e.Y - lastMouse.Y;
   404→
   405→        // 팬 이동 (좌우 동시 클릭)
   406→        if (isPanning)
   407→        {
   408→            panOffsetX += dx;
   409→            panOffsetY += dy;
   410→            lastMouse = e.Location;
   411→            picViewer.Invalidate();
   412→        }
   413→        // 회전 (좌클릭)
   414→        else if (isDragging)
   415→        {
   416→            viewAngleZ += dx * 0.5;
   417→            viewAngleX += dy * 0.5;
   418→
   419→            // 상하 각도 제한
   420→            viewAngleX = Math.Max(-90, Math.Min(90, viewAngleX));
   421→
   422→            lastMouse = e.Location;
   423→            picViewer.Invalidate();
   424→        }
   425→    }
   426→
   427→    private void PicViewer_MouseUp(object? sender, MouseEventArgs e)
   428→    {
   429→        // 둘 다 떼면 드래그 종료
   430→        if ((Control.MouseButtons & MouseButtons.Left) == 0 &&
   431→            (Control.MouseButtons & MouseButtons.Right) == 0)
   432→        {
   433→            isDragging = false;
   434→            isPanning = false;
   435→            picViewer.Cursor = Cursors.Default;
   436→        }
   437→    }
