   439→    // 마우스 휠 (줌)
   440→    private void PicViewer_MouseWheel(object? sender, MouseEventArgs e)
   441→    {
   442→        if (e.Delta > 0)
   443→            zoom *= 1.1;
   444→        else
   445→            zoom /= 1.1;
   446→
   447→        zoom = Math.Max(0.3, Math.Min(5, zoom));
   448→        picViewer.Invalidate();
   449→    }
